+  // Find a good break point (word boundary)
+  let truncateAt = targetChars;
+  while (truncateAt > 0 && !/\s/.test(text[truncateAt])) {
+    truncateAt--;
+  }
+
+  if (truncateAt === 0) {
+    truncateAt = targetChars;
+  }
